    {"path": "EldenRingModManager.sln", "content": "\nMicrosoft Visual Studio Solution File, Format Version 12.00\n# Visual Studio Version 17\nVisualStudioVersion = 17.0.31903.59\nMinimumVisualStudioVersion = 10.0.40219.1\nProject(\"{FAE04EC0-301F-11D3-BF4B-00C04F79EFBC}\") = \"EldenRingModManager\", \"EldenRingModManager.csproj\", \"{A1B2C3D4-E5F6-7890-ABCD-EF1234567890}\"\nEndProject\nGlobal\n\tGlobalSection(SolutionConfigurationPlatforms) = preSolution\n\t\tDebug|Any CPU = Debug|Any CPU\n\t\tRelease|Any CPU = Release|Any CPU\n\tEndGlobalSection\n\tGlobalSection(ProjectConfigurationPlatforms) = postSolution\n\t\t{A1B2C3D4-E5F6-7890-ABCD-EF1234567890}.Debug|Any CPU.ActiveCfg = Debug|Any CPU\n\t\t{A1B2C3D4-E5F6-7890-ABCD-EF1234567890}.Debug|Any CPU.Build.0 = Debug|Any CPU\n\t\t{A1B2C3D4-E5F6-7890-ABCD-EF1234567890}.Release|Any CPU.ActiveCfg = Release|Any CPU\n\t\t{A1B2C3D4-E5F6-7890-ABCD-EF1234567890}.Release|Any CPU.Build.0 = Release|Any CPU\n\tEndGlobalSection\nEndGlobal\n"},
    {"path": "EldenRingModManager.csproj", "content": "<Project Sdk=\"Microsoft.NET.Sdk\">\n  <PropertyGroup>\n    <OutputType>Exe</OutputType>\n    <TargetFramework>net8.0</TargetFramework>\n    <RootNamespace>EldenRingModManager</RootNamespace>\n    <ImplicitUsings>enable</ImplicitUsings>\n    <Nullable>enable</Nullable>\n  </PropertyGroup>\n  <ItemGroup>\n    <PackageReference Include=\"Newtonsoft.Json\" Version=\"13.0.3\" />\n  </ItemGroup>\n</Project>\n"},
    {"path": "Program.cs", "content": "using System;\nusing System.IO;\nusing System.Linq;\nusing EldenRingModManager.Models;\nusing EldenRingModManager.Services;\n\nnamespace EldenRingModManager;\n\n/// <summary>\n/// Entry point for the Elden Ring Mod Manager.\n/// Provides a simple CLI to list, enable, and disable mods.\n/// </summary>\ninternal class Program\n{\n    private static ModManager _modManager = null!;\n\n    static void Main(string[] args)\n    {\n        // Default mod directory: \"mods\" in the current working directory.\n        string modDirectory = Path.Combine(Directory.GetCurrentDirectory(), \"mods\");\n        if (args.Length > 0)\n        {\n            modDirectory = args[0];\n        }\n\n        Console.WriteLine($\"Elden Ring Mod Manager - Mod Directory: {modDirectory}\");\n        Console.WriteLine();\n\n        if (!Directory.Exists(modDirectory))\n        {\n            Console.WriteLine($\"Error: Mod directory '{modDirectory}' does not exist.\");\n            return;\n        }\n\n        _modManager = new ModManager(modDirectory);\n        _modManager.LoadMods();\n\n        bool running = true;\n        while (running)\n        {\n            Console.WriteLine(\"Available commands:\");\n            Console.WriteLine(\"  list       - List all mods and their status\");\n            Console.WriteLine(\"  enable <id>- Enable a mod by its ID\");\n            Console.WriteLine(\"  disable <id>- Disable a mod by its ID\");\n            Console.WriteLine(\"  exit       - Exit the application\");\n            Console.Write(\"> \");\n            string? input = Console.ReadLine();\n            if (string.IsNullOrWhiteSpace(input))\n                continue;\n\n            string[] parts = input.Split(' ', StringSplitOptions.RemoveEmptyEntries);\n            string command = parts[0].ToLowerInvariant();\n\n            switch (command)\n            {\n                case \"list\":\n                    ListMods();\n                    break;\n                case \"enable\":\n                    if (parts.Length < 2)\n                    {\n                        Console.WriteLine(\"Usage: enable <mod_id>\");\n                    }\n                    else\n                    {\n                        EnableMod(parts[1]);\n                    }\n                    break;\n                case \"disable\":\n                    if (parts.Length < 2)\n                    {\n                        Console.WriteLine(\"Usage: disable <mod_id>\");\n                    }\n                    else\n                    {\n                        DisableMod(parts[1]);\n                    }\n                    break;\n                case \"exit\":\n                    running = false;\n                    break;\n                default:\n                    Console.WriteLine($\"Unknown command: {command}\");\n                    break;\n            }\n            Console.WriteLine();\n        }\n    }\n\n    private static void ListMods()\n    {\n        var mods = _modManager.GetAllMods();\n        if (!mods.Any())\n        {\n            Console.WriteLine(\"No mods found.\");\n            return;\n        }\n\n        Console.WriteLine(\"Mods:\");\n        foreach (var mod in mods)\n        {\n            string status = mod.IsEnabled ? \"[Enabled]\" : \"[Disabled]\";\n            Console.WriteLine($\"  {mod.Id}: {mod.Name} {status}\");\n        }\n    }\n\n    private static void EnableMod(string modId)\n    {\n        var mod = _modManager.GetModById(modId);\n        if (mod == null)\n        {\n            Console.WriteLine($\"Mod with ID '{modId}' not found.\");\n            return;\n        }\n\n        if (_modManager.EnableMod(modId, out string? error))\n        {\n            Console.WriteLine($\"Enabled mod: {mod.Name}\");\n        }\n        else\n        {\n            Console.WriteLine($\"Failed to enable mod: {error}\");\n        }\n    }\n\n    private static void DisableMod(string modId)\n    {\n        var mod = _modManager.GetModById(modId);\n        if (mod == null)\n        {\n            Console.WriteLine($\"Mod with ID '{modId}' not found.\");\n            return;\n        }\n\n        if (_modManager.DisableMod(modId, out string? error))\n        {\n            Console.WriteLine($\"Disabled mod: {mod.Name}\");\n        }\n        else\n        {\n            Console.WriteLine($\"Failed to disable mod: {error}\");\n        }\n    }\n}\n"},
    {"path": "Models/ModInfo.cs", "content": "namespace EldenRingModManager.Models;\n\n/// <summary>\n/// Represents a single Elden Ring mod with its metadata and status.\n/// </summary>\npublic class ModInfo\n{\n    /// <summary>\n    /// Unique identifier for the mod (e.g., directory name).\n    /// </summary>\n    public string Id { get; set; } = string.Empty;\n\n    /// <summary>\n    /// Human-readable name of the mod.\n    /// </summary>\n    public string Name { get; set; } = string.Empty;\n\n    /// <summary>\n    /// Path to the mod's directory on disk.\n    /// </summary>\n    public string DirectoryPath { get; set; } = string.Empty;\n\n    /// <summary>\n    /// Indicates whether the mod is currently enabled.\n    /// </summary>\n    public bool IsEnabled { get; set; }\n\n    /// <summary>\n    /// Version string from mod metadata, if available.\n    /// </summary>\n    public string Version { get; set; } = \"1.0.0\";\n\n    /// <summary>\n    /// Description of the mod, if available.\n    /// </summary>\n    public string Description { get; set; } = string.Empty;\n}\n"},
    {"path": "Models/ModConfig.cs", "content": "using System.Collections.Generic;\nusing Newtonsoft.Json;\n\nnamespace EldenRingModManager.Models;\n\n/// <summary>\n/// Represents the configuration file (mods_config.json) that tracks enabled/disabled mods.\n/// </summary>\npublic class ModConfig\n{\n    /// <summary>\n    /// List of mod IDs that are currently enabled.\n    /// </summary>\n    [JsonProperty(\"enabled_mods\")]\n    public List<string> EnabledMods { get; set; } = new List<string>();\n\n    /// <summary>\n    /// Path to the Elden Ring game executable (optional, for future launch functionality).\n    /// </summary>\n    [JsonProperty(\"game_path\")]\n    public string? GamePath { get; set; }\n}\n"},
    {"path": "Services/ModManager.cs", "content": "using System;\nusing System.Collections.Generic;\nusing System.IO;\nusing System.Linq;\nusing EldenRingModManager.Models;\nusing Newtonsoft.Json;\n\nnamespace EldenRingModManager.Services;\n\n/// <summary>\n/// Core service for managing Elden Ring mods: loading, enabling, disabling.\n/// Mods are stored as subdirectories inside a specified mod directory.\n/// Each mod directory must contain a \"mod_info.json\" file with metadata.\n/// Enabled/disabled state is persisted in \"mods_config.json\" at the root of the mod directory.\n/// </summary>\npublic class ModManager\n{\n    private readonly string _modDirectory;\n    private readonly string _configFilePath;\n    private ModConfig _config;\n    private List<ModInfo> _mods;\n\n    /// <summary>\n    /// Initializes a new instance of the <see cref=\"ModManager\"/> class.\n    /// </summary>\n    /// <param name=\"modDirectory\">Absolute or relative path to the directory containing mod subfolders.</param>\n    public ModManager(string modDirectory)\n    {\n        _modDirectory = modDirectory;\n        _configFilePath = Path.Combine(_modDirectory, \"mods_config.json\");\n        _config = new ModConfig();\n        _mods = new List<ModInfo>();\n    }\n\n    /// <summary>\n    /// Scans the mod directory for mods and loads their metadata.\n    /// Reads the config file to determine which mods are enabled.\n    /// </summary>\n    public void LoadMods()\n    {\n        // Load configuration\n        if (File.Exists(_configFilePath))\n        {\n            string json = File.ReadAllText(_configFilePath);\n            _config = JsonConvert.DeserializeObject<ModConfig>(json) ?? new ModConfig();\n        }\n        else\n        {\n            _config = new ModConfig();\n        }\n\n        // Scan for mod directories\n        _mods.Clear();\n        string[] subDirectories = Directory.GetDirectories(_modDirectory);\n        foreach (string dir in subDirectories)\n        {\n            string dirName = Path.GetFileName(dir);\n            string infoFilePath = Path.Combine(dir, \"mod_info.json\");\n\n            ModInfo mod = new ModInfo\n            {\n                Id = dirName,\n                Name = dirName,\n                DirectoryPath = dir,\n                IsEnabled = _config.EnabledMods.Contains(dirName)\n            };\n\n            // Try to load detailed metadata from mod_info.json\n            if (File.Exists(infoFilePath))\n            {\n                try\n                {\n                    string infoJson = File.ReadAllText(infoFilePath);\n                    var info = JsonConvert.DeserializeObject<ModInfo>(infoJson);\n                    if (info != null)\n                    {\n                        mod.Name = string.IsNullOrWhiteSpace(info.Name) ? dirName : info.Name;\n                        mod.Version = string.IsNullOrWhiteSpace(info.Version) ? \"1.0.0\" : info.Version;\n                        mod.Description = info.Description ?? string.Empty;\n                    }\n                }\n                catch (Exception ex)\n                {\n                    Console.WriteLine($\"Warning: Failed to parse mod_info.json for '{dirName}': {ex.Message}\");\n                }\n            }\n\n            _mods.Add(mod);\n        }\n    }\n\n    /// <summary>\n    /// Returns a read-only list of all loaded mods.\n    /// </summary>\n    public IReadOnlyList<ModInfo> GetAllMods()\n    {\n        return _mods.AsReadOnly();\n    }\n\n    /// <summary>\n    /// Finds a mod by its unique ID.\n    /// </summary>\n    /// <param name=\"modId\">The mod's ID (directory name).</param>\n    /// <returns>The mod if found, otherwise null.</returns>\n    public ModInfo? GetModById(string modId)\n    {\n        return _mods.FirstOrDefault(m => m.Id.Equals(modId, StringComparison.OrdinalIgnoreCase));\n    }\n\n    /// <summary>\n    /// Enables a mod by adding its ID to the enabled list and persisting the config.\n    /// Also renames the mod directory by removing a \".disabled\" suffix if present.\n    /// </summary>\n    /// <param name=\"modId\">The mod ID to enable.</param>\n    /// <param name=\"error\">Outputs an error message if enabling fails.</param>\n    /// <returns>True if successful, false otherwise.</returns>\n    public bool EnableMod(string modId, out string? error)\n    {\n        error = null;\n        var mod = GetModById(modId);\n        if (mod == null)\n        {\n            error = \"Mod not found.\";\n            return false;\n        }\n\n        if (mod.IsEnabled)\n        {\n            return true; // Already enabled\n        }\n\n        // Remove .disabled suffix from directory name if present\n        string dirPath = mod.DirectoryPath;\n        if (dirPath.EndsWith(\".disabled\", StringComparison.OrdinalIgnoreCase))\n        {\n            string newDirPath = dirPath.Substring(0, dirPath.Length - \".disabled\".Length);\n            try\n            {\n                Directory.Move(dirPath, newDirPath);\n                mod.DirectoryPath = newDirPath;\n            }\n            catch (Exception ex)\n            {\n                error = $\"Failed to rename directory: {ex.Message}\";\n                return false;\n            }\n        }\n\n        // Update config\n        if (!_config.EnabledMods.Contains(modId))\n        {\n            _config.EnabledMods.Add(modId);\n        }\n        mod.IsEnabled = true;\n        SaveConfig();\n        return true;\n    }\n\n    /// <summary>\n    /// Disables a mod by removing its ID from the enabled list and persisting the config.\n    /// Also renames the mod directory by appending a \".disabled\" suffix.\n    /// </summary>\n    /// <param name=\"modId\">The mod ID to disable.</param>\n    /// <param name=\"error\">Outputs an error message if disabling fails.</param>\n    /// <returns>True if successful, false otherwise.</returns>\n    public bool DisableMod(string modId, out string? error)\n    {\n        error = null;\n        var mod = GetModById(modId);\n        if (mod == null)\n        {\n            error = \"Mod not found.\";\n            return false;\n        }\n\n        if (!mod.IsEnabled)\n        {\n            return true; // Already disabled\n        }\n\n        // Append .disabled suffix to directory name\n        string dirPath = mod.DirectoryPath;\n        if (!dirPath.EndsWith(\".disabled\", StringComparison.OrdinalIgnoreCase))\n        {\n            string newDirPath = dirPath + \".disabled\";\n            try\n            {\n                Directory.Move(dirPath, newDirPath);\n                mod.DirectoryPath = newDirPath;\n            }\n            catch (Exception ex)\n            {\n                error = $\"Failed to rename directory: {ex.Message}\";\n                return false;\n            }\n        }\n\n        // Update config\n        _config.EnabledMods.Remove(modId);\n        mod.IsEnabled = false;\n        SaveConfig();\n        return true;\n    }\n\n    /// <summary>\n    /// Persists the current mod configuration to disk as JSON.\n    /// </summary>\n    private void SaveConfig()\n    {\n        string json = JsonConvert.SerializeObject(_config, Formatting.Indented);\n        File.WriteAllText(_configFilePath, json);\n    }\n}\n"},
    {"path": "tests/ModManagerTests.cs", "content": "using System;\nusing System.IO;\nusing EldenRingModManager.Models;\nusing EldenRingModManager.Services;\nusing Newtonsoft.Json;\nusing Xunit;\n\nnamespace EldenRingModManager.Tests;\n\n/// <summary>\n/// Unit tests for the ModManager service.\n/// Uses temporary directories to avoid affecting real mod setups.\n/// </summary>\npublic class ModManagerTests : IDisposable\n{\n    private readonly string _tempDir;\n    private readonly string _modDir;\n    private readonly ModManager _manager;\n\n    public ModManagerTests()\n    {\n        // Create a temporary directory for each test\n        _tempDir = Path.Combine(Path.GetTempPath(), Guid.NewGuid().ToString());\n        _modDir = Path.Combine(_tempDir, \"mods\");\n        Directory.CreateDirectory(_modDir);\n        _manager
